// Bookmark Manager API — entrypoint
// See PRODUCT_SPEC.md for full requirements
// The agent will build this out across tasks T1-T6

import bcrypt from "bcryptjs";
import express, { type NextFunction, type Request, type Response } from "express";
import Database from "better-sqlite3";
import jwt from "jsonwebtoken";

const app = express();
const PORT = 3000;
const JWT_SECRET = "benchmark-secret";
const db: Database.Database = new Database("data.db");

app.use(express.json());

db.pragma("foreign_keys = ON");

db.exec(`
  CREATE TABLE IF NOT EXISTS users (
    id INTEGER PRIMARY KEY,
    email TEXT NOT NULL UNIQUE,
    password_hash TEXT NOT NULL,
    created_at TEXT NOT NULL
  );

  CREATE TABLE IF NOT EXISTS folders (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    name TEXT NOT NULL,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE
  );

  CREATE TABLE IF NOT EXISTS bookmarks (
    id INTEGER PRIMARY KEY,
    user_id INTEGER NOT NULL,
    url TEXT NOT NULL,
    title TEXT NOT NULL,
    description TEXT,
    folder_id INTEGER,
    created_at TEXT NOT NULL,
    updated_at TEXT NOT NULL,
    FOREIGN KEY (user_id) REFERENCES users(id) ON DELETE CASCADE,
    FOREIGN KEY (folder_id) REFERENCES folders(id) ON DELETE SET NULL
  )
`);

function ensureColumn(tableName: "bookmarks" | "folders", columnName: string, alterSql: string): void {
  const columns = db.prepare(`PRAGMA table_info(${tableName})`).all() as Array<{ name: string }>;
  if (!columns.some((column) => column.name === columnName)) {
    db.exec(alterSql);
  }
}

ensureColumn("bookmarks", "folder_id", "ALTER TABLE bookmarks ADD COLUMN folder_id INTEGER REFERENCES folders(id) ON DELETE SET NULL");
ensureColumn("bookmarks", "user_id", "ALTER TABLE bookmarks ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");
ensureColumn("folders", "user_id", "ALTER TABLE folders ADD COLUMN user_id INTEGER REFERENCES users(id) ON DELETE CASCADE");

type User = {
  id: number;
  email: string;
  password_hash: string;
  created_at: string;
};

type PublicUser = {
  id: number;
  email: string;
  created_at: string;
};

type Bookmark = {
  id: number;
  user_id: number;
  url: string;
  title: string;
  description: string | null;
  folder_id: number | null;
  created_at: string;
  updated_at: string;
};

type Folder = {
  id: number;
  user_id: number;
  name: string;
  created_at: string;
  updated_at: string;
};

declare global {
  namespace Express {
    interface Request {
      userId?: number;
    }
  }
}

function toPublicUser(user: User): PublicUser {
  return {
    id: user.id,
    email: user.email,
    created_at: user.created_at,
  };
}

function isNonEmptyString(value: unknown): value is string {
  return typeof value === "string" && value.trim().length > 0;
}

function isValidEmail(value: string): boolean {
  return /^[^\s@]+@[^\s@]+\.[^\s@]+$/.test(value);
}

function isValidPassword(value: unknown): value is string {
  return typeof value === "string" && value.length >= 8;
}

function isValidUrl(value: string): boolean {
  try {
    new URL(value);
    return true;
  } catch {
    return false;
  }
}

function getUserByEmail(email: string): User | undefined {
  return db.prepare("SELECT id, email, password_hash, created_at FROM users WHERE email = ?").get(email) as
    | User
    | undefined;
}

function getUserById(id: number): User | undefined {
  return db.prepare("SELECT id, email, password_hash, created_at FROM users WHERE id = ?").get(id) as User | undefined;
}

function getBookmark(id: number, userId: number): Bookmark | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE id = ? AND user_id = ?
      `,
    )
    .get(id, userId) as Bookmark | undefined;
}

function getFolder(id: number, userId: number): Folder | undefined {
  return db
    .prepare(
      `
        SELECT id, user_id, name, created_at, updated_at
        FROM folders
        WHERE id = ? AND user_id = ?
      `,
    )
    .get(id, userId) as Folder | undefined;
}

function parseFolderId(value: unknown): number | null | undefined {
  if (value === undefined) {
    return undefined;
  }

  if (value === null) {
    return null;
  }

  if (typeof value === "number" && Number.isInteger(value) && value > 0) {
    return value;
  }

  return undefined;
}

function folderExists(id: number, userId: number): boolean {
  return getFolder(id, userId) !== undefined;
}

function getBookmarksForFolder(folderId: number, userId: number): Bookmark[] {
  return db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE folder_id = ? AND user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(folderId, userId) as Bookmark[];
}

function requireUserId(req: Request): number {
  if (typeof req.userId !== "number") {
    throw new Error("authenticated route missing userId");
  }

  return req.userId;
}

function authenticate(req: Request, res: Response, next: NextFunction): Response | void {
  const authorization = req.header("Authorization");
  const [scheme, token] = authorization?.split(" ") ?? [];

  if (scheme !== "Bearer" || !token) {
    return res.status(401).json({ error: "authentication required" });
  }

  try {
    const payload = jwt.verify(token, JWT_SECRET);
    const userId = typeof payload === "object" && payload !== null ? payload.userId : undefined;

    if (typeof userId !== "number" || !Number.isInteger(userId) || !getUserById(userId)) {
      return res.status(401).json({ error: "invalid token" });
    }

    req.userId = userId;
    return next();
  } catch {
    return res.status(401).json({ error: "invalid token" });
  }
}

app.get("/health", (_req, res) => {
  res.status(200).json({ status: "ok" });
});

app.post("/auth/register", async (req, res) => {
  const { email, password } = req.body as { email?: unknown; password?: unknown };

  if (!isNonEmptyString(email) || !isValidEmail(email.trim())) {
    return res.status(400).json({ error: "email must be valid" });
  }

  if (!isValidPassword(password)) {
    return res.status(400).json({ error: "password must be at least 8 characters" });
  }

  const normalizedEmail = email.trim().toLowerCase();
  if (getUserByEmail(normalizedEmail)) {
    return res.status(409).json({ error: "email already exists" });
  }

  const now = new Date().toISOString();
  const passwordHash = await bcrypt.hash(password, 10);

  try {
    const result = db
      .prepare(
        `
          INSERT INTO users (email, password_hash, created_at)
          VALUES (?, ?, ?)
        `,
      )
      .run(normalizedEmail, passwordHash, now);

    const user = getUserById(Number(result.lastInsertRowid));
    return res.status(201).json(user ? toPublicUser(user) : undefined);
  } catch (error) {
    if (error instanceof Error && error.message.includes("UNIQUE")) {
      return res.status(409).json({ error: "email already exists" });
    }

    throw error;
  }
});

app.post("/auth/login", async (req, res) => {
  const { email, password } = req.body as { email?: unknown; password?: unknown };

  if (!isNonEmptyString(email) || !isValidEmail(email.trim()) || typeof password !== "string") {
    return res.status(400).json({ error: "email and password are required" });
  }

  const user = getUserByEmail(email.trim().toLowerCase());
  if (!user || !(await bcrypt.compare(password, user.password_hash))) {
    return res.status(401).json({ error: "invalid credentials" });
  }

  const token = jwt.sign({ userId: user.id }, JWT_SECRET);
  return res.status(200).json({ token });
});

app.use("/bookmarks", authenticate);
app.use("/folders", authenticate);

app.post("/bookmarks", (req, res) => {
  const userId = requireUserId(req);
  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (!isNonEmptyString(url)) {
    return res.status(400).json({ error: "url is required" });
  }

  if (!isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (!isNonEmptyString(title)) {
    return res.status(400).json({ error: "title is required" });
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must be an existing folder id or null" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId, userId)) {
    return res.status(400).json({ error: "folder_id does not reference an existing folder" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO bookmarks (user_id, url, title, description, folder_id, created_at, updated_at)
        VALUES (?, ?, ?, ?, ?, ?, ?)
      `,
    )
    .run(
      userId,
      url.trim(),
      title.trim(),
      typeof description === "string" && description.length > 0 ? description : null,
      parsedFolderId ?? null,
      now,
      now,
    );

  const bookmark = getBookmark(Number(result.lastInsertRowid), userId);
  return res.status(201).json(bookmark);
});

app.get("/bookmarks", (req, res) => {
  const userId = requireUserId(req);
  const bookmarks = db
    .prepare(
      `
        SELECT id, user_id, url, title, description, folder_id, created_at, updated_at
        FROM bookmarks
        WHERE user_id = ?
        ORDER BY id ASC
      `,
    )
    .all(userId) as Bookmark[];

  res.status(200).json(bookmarks);
});

app.get("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const bookmark = Number.isInteger(id) ? getBookmark(id, userId) : undefined;

  if (!bookmark) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(200).json(bookmark);
});

app.put("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getBookmark(id, userId) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  const { url, title, description, folder_id } = req.body as {
    url?: unknown;
    title?: unknown;
    description?: unknown;
    folder_id?: unknown;
  };

  if (url !== undefined && !isNonEmptyString(url)) {
    return res.status(400).json({ error: "url must be a non-empty string" });
  }

  if (typeof url === "string" && !isValidUrl(url)) {
    return res.status(400).json({ error: "url must be a valid URL" });
  }

  if (title !== undefined && !isNonEmptyString(title)) {
    return res.status(400).json({ error: "title must be a non-empty string" });
  }

  const parsedFolderId = parseFolderId(folder_id);
  if (folder_id !== undefined && parsedFolderId === undefined) {
    return res.status(400).json({ error: "folder_id must be an existing folder id or null" });
  }

  if (typeof parsedFolderId === "number" && !folderExists(parsedFolderId, userId)) {
    return res.status(400).json({ error: "folder_id does not reference an existing folder" });
  }

  const nextUrl = typeof url === "string" ? url.trim() : existing.url;
  const nextTitle = typeof title === "string" ? title.trim() : existing.title;
  const nextDescription =
    description === undefined
      ? existing.description
      : typeof description === "string" && description.length > 0
        ? description
        : null;
  const nextFolderId = folder_id === undefined ? existing.folder_id : parsedFolderId;
  const updatedAt = new Date().toISOString();

  db.prepare(
    `
      UPDATE bookmarks
      SET url = ?, title = ?, description = ?, folder_id = ?, updated_at = ?
      WHERE id = ? AND user_id = ?
    `,
  ).run(nextUrl, nextTitle, nextDescription, nextFolderId, updatedAt, id, userId);

  return res.status(200).json(getBookmark(id, userId));
});

app.delete("/bookmarks/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const result = Number.isInteger(id)
    ? db.prepare("DELETE FROM bookmarks WHERE id = ? AND user_id = ?").run(id, userId)
    : { changes: 0 };

  if (result.changes === 0) {
    return res.status(404).json({ error: "bookmark not found" });
  }

  return res.status(204).send();
});

app.post("/folders", (req, res) => {
  const userId = requireUserId(req);
  const { name } = req.body as { name?: unknown };

  if (!isNonEmptyString(name)) {
    return res.status(400).json({ error: "name is required" });
  }

  const now = new Date().toISOString();
  const result = db
    .prepare(
      `
        INSERT INTO folders (user_id, name, created_at, updated_at)
        VALUES (?, ?, ?, ?)
      `,
    )
    .run(userId, name.trim(), now, now);

  return res.status(201).json(getFolder(Number(result.lastInsertRowid), userId));
});

app.get("/folders", (req, res) => {
  const userId = requireUserId(req);
  const folders = db
    .prepare("SELECT id, user_id, name, created_at, updated_at FROM folders WHERE user_id = ? ORDER BY id ASC")
    .all(userId) as Folder[];

  return res.status(200).json(folders);
});

app.get("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const folder = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!folder) {
    return res.status(404).json({ error: "folder not found" });
  }

  return res.status(200).json({ ...folder, bookmarks: getBookmarksForFolder(id, userId) });
});

app.put("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const { name } = req.body as { name?: unknown };

  if (name !== undefined && !isNonEmptyString(name)) {
    return res.status(400).json({ error: "name must be a non-empty string" });
  }

  const updatedAt = new Date().toISOString();
  db.prepare("UPDATE folders SET name = ?, updated_at = ? WHERE id = ? AND user_id = ?").run(
    typeof name === "string" ? name.trim() : existing.name,
    updatedAt,
    id,
    userId,
  );

  return res.status(200).json(getFolder(id, userId));
});

app.delete("/folders/:id", (req, res) => {
  const userId = requireUserId(req);
  const id = Number(req.params.id);
  const existing = Number.isInteger(id) ? getFolder(id, userId) : undefined;

  if (!existing) {
    return res.status(404).json({ error: "folder not found" });
  }

  const transaction = db.transaction((folderId: number, ownerId: number) => {
    db.prepare("UPDATE bookmarks SET folder_id = NULL, updated_at = ? WHERE folder_id = ? AND user_id = ?").run(
      new Date().toISOString(),
      folderId,
      ownerId,
    );
    db.prepare("DELETE FROM folders WHERE id = ? AND user_id = ?").run(folderId, ownerId);
  });
  transaction(id, userId);

  return res.status(204).send();
});

app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

export default app;
export { db };

